#!/usr/bin/env node
// Basketball data generator - regenerates basketball-data.js
// Usage: node _gen_bball.js

'use strict';

const fs = require('fs');
const path = require('path');

const DATA_B64 = '';

const content = Buffer.from(DATA_B64, 'base64').toString('utf-8');
const outPath = path.join(__dirname, 'basketball-data.js');
fs.writeFileSync(outPath, content, 'utf-8');
console.log('basketball-data.js generated successfully! (' + content.split('\n').length + ' lines)');
